class TextEditor {

    private StringBuilder text;
    private int cursorPosition;

    public TextEditor() {
        text = new StringBuilder();
        cursorPosition = 0;
    }

    public void addText(String text) {
        this.text.insert(cursorPosition, text);
        cursorPosition += text.length();
    }

    public int deleteText(int k) {
        int deleted = Math.min(k, cursorPosition);
        cursorPosition -= deleted;
        return deleted;
    }

    public String cursorLeft(int k) {
        cursorPosition = Math.max(0, cursorPosition - k);
        return text.substring(Math.max(0, cursorPosition - 10), cursorPosition);
    }

    public String cursorRight(int k) {
        cursorPosition = Math.min(text.length(), cursorPosition + k);
        return text.substring(Math.max(0, cursorPosition - 10), cursorPosition);
    }
}
```

efficiency: HIGH
time complexity: O(n + k) where n is the length of the text and k is the number of operations
space complexity: O(n)
